fn simple_single_statement_fast_path_sql(sql: &str) -> Option<&str> {
    let trimmed = sql.trim();
    if trimmed.is_empty() {
        return None;
    }
    let trimmed = trimmed.strip_suffix(';').unwrap_or(trimmed).trim_end();
    if trimmed.is_empty() || trimmed.contains(';') {
        return None;
    }
    Some(trimmed)
}

fn parse_simple_count_star_sql(sql: &str) -> Option<SimpleCountSqlPlan<'_>> {
    const PREFIX: &str = "select count(*) from ";
    let trimmed = sql.trim();
    if !trimmed.is_ascii()
        || trimmed.len() <= PREFIX.len()
        || !trimmed[..PREFIX.len()].eq_ignore_ascii_case(PREFIX)
    {
        return None;
    }
    let table_name = trimmed[PREFIX.len()..].trim();
    if !is_simple_sql_identifier(table_name) {
        return None;
    }
    Some(SimpleCountSqlPlan { table_name })
}

fn parse_simple_row_id_projection_sql(sql: &str) -> Option<SimpleRowIdProjectionSqlPlan<'_>> {
    let trimmed = sql.trim();
    if !trimmed.is_ascii() {
        return None;
    }
    if trimmed.len() <= 7 || !trimmed[..7].eq_ignore_ascii_case("select ") {
        return None;
    }
    let from_index = find_ascii_case_insensitive(trimmed, " from ")?;
    let where_marker = " where ";
    let where_index = find_ascii_case_insensitive(&trimmed[from_index + 6..], where_marker)
        .map(|index| from_index + 6 + index)?;
    let filter_tail = &trimmed[where_index + where_marker.len()..];
    if contains_ascii_case_insensitive(filter_tail, " order ")
        || contains_ascii_case_insensitive(filter_tail, " limit ")
        || contains_ascii_case_insensitive(filter_tail, " group ")
    {
        return None;
    }

    let projection_sql = trimmed[6..from_index].trim();
    let table_name = trimmed[from_index + 6..where_index].trim();
    let filter_sql = trimmed[where_index + where_marker.len()..].trim();
    if projection_sql.is_empty() || !is_simple_sql_identifier(table_name) {
        return None;
    }
    let mut projection_columns = Vec::new();
    for column in projection_sql.split(',') {
        let column = column.trim();
        if !is_simple_sql_identifier(column) {
            return None;
        }
        projection_columns.push(column);
    }
    let (left, right) = filter_sql.split_once('=')?;
    let left = left.trim();
    let right = right.trim();
    let (filter_column, param_index) = if let Some(param_index) = parse_positional_param(right) {
        (left, param_index)
    } else if let Some(param_index) = parse_positional_param(left) {
        (right, param_index)
    } else {
        return None;
    };
    if !is_simple_sql_identifier(filter_column) {
        return None;
    }
    Some(SimpleRowIdProjectionSqlPlan {
        table_name,
        projection_columns,
        filter_column,
        param_index,
    })
}

fn parse_simple_row_id_range_projection_sql(
    sql: &str,
) -> Option<SimpleRowIdRangeProjectionSqlPlan<'_>> {
    let trimmed = sql.trim();
    if !trimmed.is_ascii() {
        return None;
    }
    if trimmed.len() <= 7 || !trimmed[..7].eq_ignore_ascii_case("select ") {
        return None;
    }
    let from_index = find_ascii_case_insensitive(trimmed, " from ")?;
    let where_marker = " where ";
    let where_index = find_ascii_case_insensitive(&trimmed[from_index + 6..], where_marker)
        .map(|index| from_index + 6 + index)?;
    let projection_sql = trimmed[6..from_index].trim();
    let table_name = trimmed[from_index + 6..where_index].trim();
    if projection_sql.is_empty() || !is_simple_sql_identifier(table_name) {
        return None;
    }

    let filter_tail = trimmed[where_index + where_marker.len()..].trim();
    let limit_marker = " limit ";
    let limit_index = find_ascii_case_insensitive(filter_tail, limit_marker)?;
    let before_limit = filter_tail[..limit_index].trim();
    let limit_sql = filter_tail[limit_index + limit_marker.len()..].trim();
    if limit_sql.is_empty()
        || contains_ascii_case_insensitive(limit_sql, " offset ")
        || limit_sql.split_ascii_whitespace().count() != 1
    {
        return None;
    }
    let limit_param_index = parse_positional_param(limit_sql)?;

    let order_marker = " order by ";
    let (filter_sql, order_column) =
        if let Some(order_index) = find_ascii_case_insensitive(before_limit, order_marker) {
            let filter_sql = before_limit[..order_index].trim();
            let order_sql = before_limit[order_index + order_marker.len()..].trim();
            let mut order_parts = order_sql.split_ascii_whitespace();
            let order_column = order_parts.next()?;
            if !is_simple_sql_identifier(order_column) {
                return None;
            }
            match order_parts.next() {
                None => {}
                Some(direction) if direction.eq_ignore_ascii_case("asc") => {}
                _ => return None,
            }
            if order_parts.next().is_some() {
                return None;
            }
            (filter_sql, Some(order_column))
        } else {
            (before_limit, None)
        };
    if filter_sql.is_empty()
        || contains_ascii_case_insensitive(filter_sql, " group ")
        || contains_ascii_case_insensitive(filter_sql, " having ")
    {
        return None;
    }

    let mut projection_columns = Vec::new();
    for column in projection_sql.split(',') {
        let column = column.trim();
        if !is_simple_sql_identifier(column) {
            return None;
        }
        projection_columns.push(column);
    }

    let mut filter_column = None;
    let mut lower_bound = None;
    let mut upper_bound = None;
    let mut remaining = filter_sql.trim();
    loop {
        let (term, rest) = if let Some(and_index) = find_ascii_case_insensitive(remaining, " and ")
        {
            (
                remaining[..and_index].trim(),
                Some(remaining[and_index + 5..].trim()),
            )
        } else {
            (remaining.trim(), None)
        };
        let (term_column, bound_kind, param_index) = parse_simple_range_param_term(term)?;
        if let Some(existing_column) = filter_column {
            if !identifiers_equal(existing_column, term_column) {
                return None;
            }
        } else {
            filter_column = Some(term_column);
        }
        let bound = PreparedSimpleRangeBoundParam {
            inclusive: bound_kind.inclusive(),
            param_index,
        };
        match bound_kind {
            SimpleRangeParamBoundKind::Lower(_) => {
                if lower_bound.replace(bound).is_some() {
                    return None;
                }
            }
            SimpleRangeParamBoundKind::Upper(_) => {
                if upper_bound.replace(bound).is_some() {
                    return None;
                }
            }
        }
        let Some(rest) = rest else {
            break;
        };
        if rest.is_empty() {
            return None;
        }
        remaining = rest;
    }
    let filter_column = filter_column?;
    if lower_bound.is_none() && upper_bound.is_none() {
        return None;
    }
    if order_column.is_some_and(|column| !identifiers_equal(column, filter_column)) {
        return None;
    }

    Some(SimpleRowIdRangeProjectionSqlPlan {
        table_name,
        projection_columns,
        filter_column,
        lower_bound,
        upper_bound,
        limit_param_index,
    })
}

type PreparedJoinColumnRef<'a> = (Option<&'a str>, &'a str);
type PreparedJoinColumnEquality<'a> = (PreparedJoinColumnRef<'a>, PreparedJoinColumnRef<'a>);

fn prepared_join_column_equality(
    constraint: &crate::sql::ast::JoinConstraint,
) -> Option<PreparedJoinColumnEquality<'_>> {
    let crate::sql::ast::JoinConstraint::On(expr) = constraint else {
        return None;
    };
    let crate::sql::ast::Expr::Binary {
        left,
        op: crate::sql::ast::BinaryOp::Eq,
        right,
    } = expr
    else {
        return None;
    };
    let crate::sql::ast::Expr::Column {
        table: left_table,
        column: left_column,
    } = left.as_ref()
    else {
        return None;
    };
    let crate::sql::ast::Expr::Column {
        table: right_table,
        column: right_column,
    } = right.as_ref()
    else {
        return None;
    };
    Some((
        (left_table.as_deref(), left_column.as_str()),
        (right_table.as_deref(), right_column.as_str()),
    ))
}

fn prepared_join_filter_param(
    filter: &crate::sql::ast::Expr,
) -> Option<(Option<&str>, &str, usize)> {
    let crate::sql::ast::Expr::Binary {
        left,
        op: crate::sql::ast::BinaryOp::Eq,
        right,
    } = filter
    else {
        return None;
    };
    if let crate::sql::ast::Expr::Column { table, column } = left.as_ref() {
        let crate::sql::ast::Expr::Parameter(param_index) = right.as_ref() else {
            return None;
        };
        return Some((
            table.as_deref(),
            column.as_str(),
            param_index.checked_sub(1)?,
        ));
    }
    if let crate::sql::ast::Expr::Column { table, column } = right.as_ref() {
        let crate::sql::ast::Expr::Parameter(param_index) = left.as_ref() else {
            return None;
        };
        return Some((
            table.as_deref(),
            column.as_str(),
            param_index.checked_sub(1)?,
        ));
    }
    None
}

fn prepared_join_column_side(
    table: Option<&str>,
    left_name: &str,
    left_alias: &Option<String>,
    right_name: &str,
    right_alias: &Option<String>,
) -> Option<SimpleJoinProjectionSide> {
    let table = table?;
    let matches_left = identifiers_equal(table, left_name)
        || left_alias
            .as_deref()
            .is_some_and(|alias| identifiers_equal(table, alias));
    let matches_right = identifiers_equal(table, right_name)
        || right_alias
            .as_deref()
            .is_some_and(|alias| identifiers_equal(table, alias));
    match (matches_left, matches_right) {
        (true, false) => Some(SimpleJoinProjectionSide::Left),
        (false, true) => Some(SimpleJoinProjectionSide::Right),
        _ => None,
    }
}

fn push_prepared_join_projection_index(indexes: &mut Vec<usize>, index: usize) -> usize {
    if let Some(position) = indexes.iter().position(|candidate| *candidate == index) {
        position
    } else {
        indexes.push(index);
        indexes.len() - 1
    }
}

fn prepared_table_generated_columns_are_stored(table: &TableSchema) -> bool {
    table
        .columns
        .iter()
        .all(|column| column.generated_sql.is_none() || column.generated_stored)
}

fn prepared_scalar_count_star(expr: &crate::sql::ast::Expr) -> bool {
    let crate::sql::ast::Expr::Aggregate {
        name,
        args,
        distinct,
        star,
        order_by,
        within_group,
    } = expr
    else {
        return false;
    };
    name.eq_ignore_ascii_case("count")
        && args.is_empty()
        && !*distinct
        && *star
        && order_by.is_empty()
        && !*within_group
}

fn prepared_scalar_sum_column<'a>(
    expr: &'a crate::sql::ast::Expr,
    table_name: &str,
    alias: &Option<String>,
) -> Option<&'a str> {
    let crate::sql::ast::Expr::Aggregate {
        name,
        args,
        distinct,
        star,
        order_by,
        within_group,
    } = expr
    else {
        return None;
    };
    if !name.eq_ignore_ascii_case("sum")
        || *distinct
        || *star
        || !order_by.is_empty()
        || *within_group
        || args.len() != 1
    {
        return None;
    }
    let crate::sql::ast::Expr::Column { table, column } = &args[0] else {
        return None;
    };
    if prepared_scalar_column_matches_table(table.as_deref(), table_name, alias) {
        Some(column.as_str())
    } else {
        None
    }
}

fn prepared_scalar_filter_param(
    filter: &crate::sql::ast::Expr,
    table_name: &str,
    alias: &Option<String>,
) -> Option<usize> {
    let crate::sql::ast::Expr::Binary {
        left,
        op: crate::sql::ast::BinaryOp::Eq,
        right,
    } = filter
    else {
        return None;
    };
    if let crate::sql::ast::Expr::Column { table, .. } = left.as_ref() {
        if prepared_scalar_column_matches_table(table.as_deref(), table_name, alias) {
            let crate::sql::ast::Expr::Parameter(param_index) = right.as_ref() else {
                return None;
            };
            return param_index.checked_sub(1);
        }
    }
    if let crate::sql::ast::Expr::Column { table, .. } = right.as_ref() {
        if prepared_scalar_column_matches_table(table.as_deref(), table_name, alias) {
            let crate::sql::ast::Expr::Parameter(param_index) = left.as_ref() else {
                return None;
            };
            return param_index.checked_sub(1);
        }
    }
    None
}

fn prepared_scalar_column_matches_table(
    table: Option<&str>,
    table_name: &str,
    alias: &Option<String>,
) -> bool {
    table.is_none_or(|qualifier| {
        identifiers_equal(qualifier, table_name)
            || alias
                .as_deref()
                .is_some_and(|alias| identifiers_equal(qualifier, alias))
    })
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum SimpleRangeParamBoundKind {
    Lower(bool),
    Upper(bool),
}

impl SimpleRangeParamBoundKind {
    fn inclusive(self) -> bool {
        match self {
            Self::Lower(inclusive) | Self::Upper(inclusive) => inclusive,
        }
    }
}

fn parse_simple_range_param_term(term: &str) -> Option<(&str, SimpleRangeParamBoundKind, usize)> {
    let (left, op, right) = split_simple_range_operator(term)?;
    if is_simple_sql_identifier(left) {
        let param_index = parse_positional_param(right)?;
        let bound = match op {
            SimpleRangeOperator::Gt => SimpleRangeParamBoundKind::Lower(false),
            SimpleRangeOperator::GtEq => SimpleRangeParamBoundKind::Lower(true),
            SimpleRangeOperator::Lt => SimpleRangeParamBoundKind::Upper(false),
            SimpleRangeOperator::LtEq => SimpleRangeParamBoundKind::Upper(true),
        };
        return Some((left, bound, param_index));
    }
    if is_simple_sql_identifier(right) {
        let param_index = parse_positional_param(left)?;
        let bound = match op {
            SimpleRangeOperator::Gt => SimpleRangeParamBoundKind::Upper(false),
            SimpleRangeOperator::GtEq => SimpleRangeParamBoundKind::Upper(true),
            SimpleRangeOperator::Lt => SimpleRangeParamBoundKind::Lower(false),
            SimpleRangeOperator::LtEq => SimpleRangeParamBoundKind::Lower(true),
        };
        return Some((right, bound, param_index));
    }
    None
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum SimpleRangeOperator {
    Gt,
    GtEq,
    Lt,
    LtEq,
}

fn split_simple_range_operator(term: &str) -> Option<(&str, SimpleRangeOperator, &str)> {
    for (token, op) in [
        (">=", SimpleRangeOperator::GtEq),
        ("<=", SimpleRangeOperator::LtEq),
        (">", SimpleRangeOperator::Gt),
        ("<", SimpleRangeOperator::Lt),
    ] {
        if let Some(index) = term.find(token) {
            let left = term[..index].trim();
            let right = term[index + token.len()..].trim();
            if left.is_empty() || right.is_empty() {
                return None;
            }
            return Some((left, op, right));
        }
    }
    None
}

fn find_ascii_case_insensitive(haystack: &str, needle: &str) -> Option<usize> {
    if needle.is_empty() {
        return Some(0);
    }
    haystack
        .as_bytes()
        .windows(needle.len())
        .position(|window| ascii_bytes_eq_ignore_ascii_case(window, needle.as_bytes()))
}

fn contains_ascii_case_insensitive(haystack: &str, needle: &str) -> bool {
    find_ascii_case_insensitive(haystack, needle).is_some()
}

fn ascii_bytes_eq_ignore_ascii_case(left: &[u8], right: &[u8]) -> bool {
    left.len() == right.len()
        && left
            .iter()
            .zip(right.iter())
            .all(|(left, right)| left.eq_ignore_ascii_case(right))
}

fn parse_positional_param(sql: &str) -> Option<usize> {
    let number = sql.strip_prefix('$')?;
    if number.is_empty() || !number.bytes().all(|byte| byte.is_ascii_digit()) {
        return None;
    }
    number.parse::<usize>().ok()?.checked_sub(1)
}

fn is_simple_sql_identifier(identifier: &str) -> bool {
    let mut chars = identifier.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    (first == '_' || first.is_ascii_alphabetic())
        && chars.all(|ch| ch == '_' || ch.is_ascii_alphanumeric())
}

fn parse_transaction_control(sql: &str) -> Option<TransactionControl> {
    let normalized = normalized_control_sql(sql);
    let upper = normalized.to_ascii_uppercase();

    match upper.as_str() {
        "BEGIN"
        | "BEGIN TRANSACTION"
        | "BEGIN DEFERRED"
        | "BEGIN DEFERRED TRANSACTION"
        | "BEGIN IMMEDIATE"
        | "BEGIN IMMEDIATE TRANSACTION"
        | "BEGIN EXCLUSIVE"
        | "BEGIN EXCLUSIVE TRANSACTION" => Some(TransactionControl::Begin),
        "COMMIT" | "END" | "END TRANSACTION" => Some(TransactionControl::Commit),
        "ROLLBACK" | "ROLLBACK TRANSACTION" => Some(TransactionControl::Rollback),
        _ => parse_savepoint_control(&normalized),
    }
}

fn parse_pragma_command(sql: &str) -> Result<Option<PragmaCommand>> {
    let trimmed = sql.trim();
    let Some(_) = trimmed
        .get(..6)
        .filter(|prefix| prefix.eq_ignore_ascii_case("PRAGMA"))
    else {
        return Ok(None);
    };
    let body = trimmed[6..].trim();
    if body.is_empty() {
        return Err(DbError::sql("PRAGMA requires a name"));
    }
    let body = body.trim_end_matches(';').trim();
    if body.is_empty() {
        return Err(DbError::sql("PRAGMA requires a name"));
    }

    if let Some(open_paren) = body.find('(') {
        let close_paren = body
            .rfind(')')
            .ok_or_else(|| DbError::sql("PRAGMA call is missing closing ')'"))?;
        if close_paren <= open_paren {
            return Err(DbError::sql("PRAGMA call has invalid parentheses"));
        }
        let name = body[..open_paren].trim();
        let argument = body[open_paren + 1..close_paren].trim();
        let trailing = body[close_paren + 1..].trim();
        if !trailing.is_empty() {
            return Err(DbError::sql("PRAGMA call has unexpected trailing content"));
        }
        let name = parse_pragma_name(name)?;
        if argument.is_empty() && name.name != PragmaName::WalCheckpoint {
            return Err(DbError::sql("PRAGMA call requires an argument"));
        }
        let accepts_call = matches!(
            name.name,
            PragmaName::TableInfo
                | PragmaName::TableXInfo
                | PragmaName::IndexList
                | PragmaName::IndexInfo
                | PragmaName::IndexXInfo
                | PragmaName::ForeignKeyList
                | PragmaName::WalCheckpoint
        );
        if !accepts_call {
            return Err(DbError::sql(format!(
                "PRAGMA {} does not accept call syntax",
                pragma_name_sql(&name.name)
            )));
        }
        let argument = if argument.is_empty() {
            None
        } else {
            Some(parse_pragma_table_argument(argument)?)
        };
        return Ok(Some(PragmaCommand::Call {
            target: name,
            argument,
        }));
    }

    let (name, value) = if let Some(eq_index) = body.find('=') {
        let name = body[..eq_index].trim();
        let value = body[eq_index + 1..].trim();
        if name.is_empty() || value.is_empty() {
            return Err(DbError::sql("PRAGMA assignment requires a name and value"));
        }
        (name, Some(value))
    } else {
        (body, None)
    };
    let pragma_name = parse_pragma_name(name)?;
    let command = if let Some(value) = value {
        let value = parse_pragma_value(value)?;
        PragmaCommand::Set(pragma_name, value)
    } else {
        PragmaCommand::Query(pragma_name)
    };
    Ok(Some(command))
}

fn parse_pragma_name(name: &str) -> Result<PragmaTarget> {
    let normalized = name.trim().to_ascii_lowercase();
    let (schema, pragma_name) = match normalized.split_once('.') {
        Some((schema, pragma_name)) => {
            let schema = match schema.trim() {
                "main" => Some(PragmaSchema::Main),
                "temp" => Some(PragmaSchema::Temp),
                _ => {
                    return Err(DbError::sql(format!(
                        "unsupported PRAGMA schema qualifier '{}'; supported qualifiers are main and temp",
                        schema
                    )));
                }
            };
            (schema, pragma_name.trim())
        }
        None => (None, normalized.as_str()),
    };
    if pragma_name.is_empty() {
        return Err(DbError::sql("PRAGMA requires a name"));
    }
    let name = match pragma_name {
        "page_size" => Ok(PragmaName::PageSize),
        "cache_size" => Ok(PragmaName::CacheSize),
        "integrity_check" => Ok(PragmaName::IntegrityCheck),
        "database_list" => Ok(PragmaName::DatabaseList),
        "quick_check" => Ok(PragmaName::QuickCheck),
        "foreign_keys" => Ok(PragmaName::ForeignKeys),
        "journal_mode" => Ok(PragmaName::JournalMode),
        "synchronous" => Ok(PragmaName::Synchronous),
        "wal_checkpoint" => Ok(PragmaName::WalCheckpoint),
        "schema_version" => Ok(PragmaName::SchemaVersion),
        "user_version" => Ok(PragmaName::UserVersion),
        "application_id" => Ok(PragmaName::ApplicationId),
        "encoding" => Ok(PragmaName::Encoding),
        "busy_timeout" => Ok(PragmaName::BusyTimeout),
        "locking_mode" => Ok(PragmaName::LockingMode),
        "temp_store" => Ok(PragmaName::TempStore),
        "table_info" => Ok(PragmaName::TableInfo),
        "table_xinfo" => Ok(PragmaName::TableXInfo),
        "table_list" => Ok(PragmaName::TableList),
        "index_list" => Ok(PragmaName::IndexList),
        "index_info" => Ok(PragmaName::IndexInfo),
        "index_xinfo" => Ok(PragmaName::IndexXInfo),
        "foreign_key_list" => Ok(PragmaName::ForeignKeyList),
        "auto_vacuum" => Err(DbError::sql(
            "PRAGMA auto_vacuum is not supported; not applicable to DecentDB storage/checkpointing",
        )),
        "cache_spill" => Err(DbError::sql(
            "PRAGMA cache_spill is not supported; no DecentDB page-cache spill policy",
        )),
        "case_sensitive_like" => Err(DbError::sql(
            "PRAGMA case_sensitive_like is not supported unless the SQL engine explicitly exposes it",
        )),
        "defer_foreign_keys" => Err(DbError::sql(
            "PRAGMA defer_foreign_keys is not supported; deferred constraints are advanced compatibility work",
        )),
        "ignore_check_constraints" => Err(DbError::sql(
            "PRAGMA ignore_check_constraints is not supported; constraints cannot be disabled",
        )),
        "mmap_size" => Err(DbError::sql(
            "PRAGMA mmap_size is not supported as a SQL runtime tuning knob",
        )),
        "optimize" => Err(DbError::sql(
            "PRAGMA optimize is not supported in this compatibility slice",
        )),
        "read_uncommitted" => Err(DbError::sql(
            "PRAGMA read_uncommitted is not supported; DecentDB does not expose dirty reads",
        )),
        "recursive_triggers" => Err(DbError::sql(
            "PRAGMA recursive_triggers is not supported without trigger recursion semantics",
        )),
        "secure_delete" => Err(DbError::sql(
            "PRAGMA secure_delete is not supported; no exact SQLite free-page overwrite mode",
        )),
        "trusted_schema" => Err(DbError::sql(
            "PRAGMA trusted_schema is not supported; DecentDB does not expose that extension model",
        )),
        _ => Err(DbError::sql(format!("unsupported PRAGMA {}", pragma_name))),
    }?;
    Ok(PragmaTarget { name, schema })
}

fn parse_pragma_value(value: &str) -> Result<PragmaValue> {
    let value = value.trim();
    if value.is_empty() {
        return Err(DbError::sql("PRAGMA assignment requires a value"));
    }
    if value.starts_with('"') {
        if !value.ends_with('"') || value.len() < 2 {
            return Err(DbError::sql("PRAGMA assignment has invalid quoted value"));
        }
        return Ok(PragmaValue::Text(
            value[1..value.len() - 1].replace("\"\"", "\""),
        ));
    }
    if value.starts_with('\'') {
        if !value.ends_with('\'') || value.len() < 2 {
            return Err(DbError::sql("PRAGMA assignment has invalid quoted value"));
        }
        return Ok(PragmaValue::Text(
            value[1..value.len() - 1].replace("''", "'"),
        ));
    }
    if let Ok(value) = value.parse::<i64>() {
        return Ok(PragmaValue::Int(value));
    }
    Ok(PragmaValue::Text(value.to_string()))
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum SynchronousRequest {
    Full,
    Normal,
    Off,
    Extra,
}

fn pragma_synchronous_mode_value(mode: WalSyncMode) -> i64 {
    match mode {
        WalSyncMode::Full => 2,
        WalSyncMode::Normal | WalSyncMode::AsyncCommit { .. } => 1,
        WalSyncMode::TestingOnlyUnsafeNoSync => 0,
    }
}

fn pragma_value_i64(value: &PragmaValue) -> Result<i64> {
    match value {
        PragmaValue::Int(value) => Ok(*value),
        PragmaValue::Text(value) => Err(DbError::sql(format!(
            "PRAGMA assignment expects a numeric value, got '{value}'"
        ))),
    }
}

fn parse_pragma_bool_value(value: &PragmaValue, pragma: &str) -> Result<bool> {
    let normalized = match value {
        PragmaValue::Int(value) => value.to_string(),
        PragmaValue::Text(value) => value.clone(),
    };
    match normalized.to_ascii_uppercase().as_str() {
        "1" | "ON" | "TRUE" | "YES" => Ok(true),
        "0" | "OFF" | "FALSE" | "NO" => Ok(false),
        _ => Err(DbError::sql(format!(
            "{} accepts ON/TRUE/YES/1 or OFF/FALSE/NO/0",
            pragma
        ))),
    }
}

fn parse_pragma_text_or_mode(value: &PragmaValue, pragma: &str) -> Result<String> {
    let value = match value {
        PragmaValue::Text(value) => value.clone(),
        PragmaValue::Int(value) => value.to_string(),
    };
    let normalized = value.trim().to_ascii_uppercase();
    if normalized.is_empty() {
        return Err(DbError::sql(format!("{pragma} requires a mode/value",)));
    }
    Ok(normalized)
}

fn parse_pragma_synchronous_request(
    value: &PragmaValue,
    pragma: &str,
) -> Result<SynchronousRequest> {
    match parse_pragma_text_or_mode(value, pragma)?.as_str() {
        "FULL" => Ok(SynchronousRequest::Full),
        "NORMAL" => Ok(SynchronousRequest::Normal),
        "OFF" => Ok(SynchronousRequest::Off),
        "EXTRA" | "3" => Ok(SynchronousRequest::Extra),
        "0" => Ok(SynchronousRequest::Off),
        "1" => Ok(SynchronousRequest::Normal),
        "2" => Ok(SynchronousRequest::Full),
        _ => Err(DbError::sql(
            "PRAGMA synchronous accepts OFF, NORMAL, FULL, EXTRA, 0, 1, 2, or 3",
        )),
    }
}

fn pragma_required_argument(target: &PragmaTarget, argument: Option<String>) -> Result<String> {
    argument.ok_or_else(|| {
        DbError::sql(format!(
            "PRAGMA {} requires an argument",
            pragma_name_sql(&target.name)
        ))
    })
}

fn pragma_schema_function_prefix(schema: Option<PragmaSchema>) -> &'static str {
    match schema {
        Some(PragmaSchema::Main) => "main.",
        Some(PragmaSchema::Temp) => "temp.",
        None => "",
    }
}

fn pragma_name_sql(name: &PragmaName) -> &'static str {
    match name {
        PragmaName::PageSize => "page_size",
        PragmaName::CacheSize => "cache_size",
        PragmaName::IntegrityCheck => "integrity_check",
        PragmaName::DatabaseList => "database_list",
        PragmaName::QuickCheck => "quick_check",
        PragmaName::ForeignKeys => "foreign_keys",
        PragmaName::JournalMode => "journal_mode",
        PragmaName::Synchronous => "synchronous",
        PragmaName::WalCheckpoint => "wal_checkpoint",
        PragmaName::SchemaVersion => "schema_version",
        PragmaName::UserVersion => "user_version",
        PragmaName::ApplicationId => "application_id",
        PragmaName::Encoding => "encoding",
        PragmaName::BusyTimeout => "busy_timeout",
        PragmaName::LockingMode => "locking_mode",
        PragmaName::TempStore => "temp_store",
        PragmaName::TableInfo => "table_info",
        PragmaName::TableXInfo => "table_xinfo",
        PragmaName::TableList => "table_list",
        PragmaName::IndexList => "index_list",
        PragmaName::IndexInfo => "index_info",
        PragmaName::IndexXInfo => "index_xinfo",
        PragmaName::ForeignKeyList => "foreign_key_list",
    }
}

fn parse_pragma_table_argument(argument: &str) -> Result<String> {
    let trimmed = argument.trim();
    if trimmed.is_empty() {
        return Err(DbError::sql("PRAGMA table_info requires a table name"));
    }
    if trimmed.starts_with('\"') {
        if !trimmed.ends_with('\"') || trimmed.len() < 2 {
            return Err(DbError::sql(
                "PRAGMA table_info has invalid quoted table name",
            ));
        }
        let inner = &trimmed[1..trimmed.len() - 1];
        return Ok(inner.replace("\"\"", "\""));
    }
    if trimmed.starts_with('\'') {
        if !trimmed.ends_with('\'') || trimmed.len() < 2 {
            return Err(DbError::sql(
                "PRAGMA table_info has invalid quoted table name",
            ));
        }
        let inner = &trimmed[1..trimmed.len() - 1];
        return Ok(inner.replace("''", "'"));
    }
    Ok(trimmed.to_string())
}

fn cache_size_pages(config: &DbConfig) -> i64 {
    let bytes = config.cache_size_mb.saturating_mul(1024 * 1024);
    let pages = (bytes / config.page_size as usize).max(1);
    i64::try_from(pages).unwrap_or(i64::MAX)
}

fn normalized_control_sql(sql: &str) -> String {
    sql.trim()
        .trim_end_matches(';')
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
}

fn parse_savepoint_control(sql: &str) -> Option<TransactionControl> {
    if let Some(name) = strip_control_prefix(sql, "SAVEPOINT ") {
        return Some(TransactionControl::Savepoint(name.to_string()));
    }
    if let Some(name) = strip_control_prefix(sql, "RELEASE SAVEPOINT ") {
        return Some(TransactionControl::ReleaseSavepoint(name.to_string()));
    }
    if let Some(name) = strip_control_prefix(sql, "RELEASE ") {
        return Some(TransactionControl::ReleaseSavepoint(name.to_string()));
    }
    if let Some(name) = strip_control_prefix(sql, "ROLLBACK TO SAVEPOINT ") {
        return Some(TransactionControl::RollbackToSavepoint(name.to_string()));
    }
    if let Some(name) = strip_control_prefix(sql, "ROLLBACK TRANSACTION TO SAVEPOINT ") {
        return Some(TransactionControl::RollbackToSavepoint(name.to_string()));
    }
    if let Some(name) = strip_control_prefix(sql, "ROLLBACK TO ") {
        return Some(TransactionControl::RollbackToSavepoint(name.to_string()));
    }
    None
}

fn strip_control_prefix<'a>(sql: &'a str, prefix: &str) -> Option<&'a str> {
    if !sql.get(..prefix.len())?.eq_ignore_ascii_case(prefix) {
        return None;
    }
    let remainder = sql[prefix.len()..].trim();
    if remainder.is_empty() {
        None
    } else {
        Some(remainder)
    }
}

fn canonical_savepoint_name(name: &str) -> String {
    name.trim().to_ascii_lowercase()
}

fn split_sql_batch(sql: &str) -> Vec<String> {
    let mut statements = Vec::new();
    let mut current = String::new();
    let mut chars = sql.chars().peekable();
    let mut in_single = false;
    let mut in_double = false;
    let mut in_line_comment = false;
    let mut in_block_comment = false;
    let mut statement_tokens = Vec::new();
    let mut trigger_body_depth = 0usize;

    while let Some(ch) = chars.next() {
        if in_line_comment {
            current.push(ch);
            if ch == '\n' {
                in_line_comment = false;
            }
            continue;
        }

        if in_block_comment {
            current.push(ch);
            if ch == '*' && matches!(chars.peek(), Some('/')) {
                current.push(chars.next().expect("comment terminator"));
                in_block_comment = false;
            }
            continue;
        }

        if in_single {
            current.push(ch);
            if ch == '\'' {
                if matches!(chars.peek(), Some('\'')) {
                    current.push(chars.next().expect("escaped quote"));
                } else {
                    in_single = false;
                }
            }
            continue;
        }

        if in_double {
            current.push(ch);
            if ch == '"' {
                if matches!(chars.peek(), Some('"')) {
                    current.push(chars.next().expect("escaped quote"));
                } else {
                    in_double = false;
                }
            }
            continue;
        }

        match ch {
            _ if ch.is_ascii_alphanumeric() || ch == '_' => {
                current.push(ch);
                let mut token = ch.to_ascii_uppercase().to_string();
                while let Some(next) = chars.peek().copied() {
                    if !(next.is_ascii_alphanumeric() || next == '_') {
                        break;
                    }
                    let next = chars.next().expect("peeked token char");
                    current.push(next);
                    token.push(next.to_ascii_uppercase());
                }
                if statement_tokens.len() < 2 {
                    statement_tokens.push(token.clone());
                }
                if statement_tokens.as_slice() == ["CREATE", "TRIGGER"] {
                    if token == "BEGIN" {
                        trigger_body_depth += 1;
                    } else if token == "END" && trigger_body_depth > 0 {
                        trigger_body_depth -= 1;
                    }
                }
            }
            '\'' => {
                in_single = true;
                current.push(ch);
            }
            '"' => {
                in_double = true;
                current.push(ch);
            }
            '-' if matches!(chars.peek(), Some('-')) => {
                current.push(ch);
                current.push(chars.next().expect("line comment start"));
                in_line_comment = true;
            }
            '/' if matches!(chars.peek(), Some('*')) => {
                current.push(ch);
                current.push(chars.next().expect("block comment start"));
                in_block_comment = true;
            }
            ';' => {
                if trigger_body_depth > 0 {
                    current.push(ch);
                } else if !current.trim().is_empty() {
                    statements.push(rewrite_legacy_trigger_body(current.trim()).into_owned());
                    current.clear();
                    statement_tokens.clear();
                    trigger_body_depth = 0;
                }
            }
            _ => current.push(ch),
        }
    }

    if !current.trim().is_empty() {
        statements.push(rewrite_legacy_trigger_body(current.trim()).into_owned());
    }
    statements
}

fn expand_sql_parameters_for_branch_log(sql: &str, params: &[Value]) -> Result<String> {
    let mut expanded = String::with_capacity(sql.len());
    let mut chars = sql.chars().peekable();
    let mut in_single = false;
    let mut in_double = false;
    let mut in_line_comment = false;
    let mut in_block_comment = false;

    while let Some(ch) = chars.next() {
        if in_line_comment {
            expanded.push(ch);
            if ch == '\n' {
                in_line_comment = false;
            }
            continue;
        }

        if in_block_comment {
            expanded.push(ch);
            if ch == '*' && matches!(chars.peek(), Some('/')) {
                expanded.push(chars.next().expect("comment terminator"));
                in_block_comment = false;
            }
            continue;
        }

        if in_single {
            expanded.push(ch);
            if ch == '\'' {
                if matches!(chars.peek(), Some('\'')) {
                    expanded.push(chars.next().expect("escaped quote"));
                } else {
                    in_single = false;
                }
            }
            continue;
        }

        if in_double {
            expanded.push(ch);
            if ch == '"' {
                if matches!(chars.peek(), Some('"')) {
                    expanded.push(chars.next().expect("escaped quote"));
                } else {
                    in_double = false;
                }
            }
            continue;
        }

        match ch {
            '\'' => {
                in_single = true;
                expanded.push(ch);
            }
            '"' => {
                in_double = true;
                expanded.push(ch);
            }
            '-' if matches!(chars.peek(), Some('-')) => {
                expanded.push(ch);
                expanded.push(chars.next().expect("line comment start"));
                in_line_comment = true;
            }
            '/' if matches!(chars.peek(), Some('*')) => {
                expanded.push(ch);
                expanded.push(chars.next().expect("block comment start"));
                in_block_comment = true;
            }
            '$' if chars.peek().is_some_and(|next| next.is_ascii_digit()) => {
                let mut digits = String::new();
                while let Some(next) = chars.peek().copied() {
                    if !next.is_ascii_digit() {
                        break;
                    }
                    digits.push(chars.next().expect("peeked digit"));
                }
                let index = digits
                    .parse::<usize>()
                    .map_err(|_| DbError::sql(format!("invalid parameter reference: ${digits}")))?;
                if index == 0 {
                    return Err(DbError::sql("parameter indexes are 1-based"));
                }
                let value = params
                    .get(index - 1)
                    .ok_or_else(|| DbError::sql(format!("parameter ${index} was not provided")))?;
                expanded.push_str(&render_branch_parameter_value_sql(value)?);
            }
            _ => expanded.push(ch),
        }
    }

    Ok(expanded)
}

fn prepared_statement_sql(sql: &str) -> Result<String> {
    let statements = split_sql_batch(sql)
        .into_iter()
        .map(|statement| statement.trim().to_string())
        .filter(|statement| !statement.is_empty())
        .collect::<Vec<_>>();
    if statements.len() != 1 {
        return Err(DbError::sql(format!(
            "expected exactly one SQL statement, got {}",
            statements.len()
        )));
    }
    let statement = statements
        .into_iter()
        .next()
        .ok_or_else(|| DbError::sql("expected exactly one SQL statement, got 0"))?;
    if parse_transaction_control(&statement).is_some() {
        return Err(DbError::sql(
            "prepared statements do not support transaction control",
        ));
    }
    reject_unsupported_collated_key_sql(&statement)?;
    Ok(statement)
}

fn reject_unsupported_collated_key_sql(sql: &str) -> Result<()> {
    let upper = sql.to_ascii_uppercase();
    if let Some(select_index) = upper.find("SELECT DISTINCT") {
        let after_distinct = select_index + "SELECT DISTINCT".len();
        let projection_end = upper[after_distinct..]
            .find(" FROM ")
            .map(|offset| after_distinct + offset)
            .unwrap_or(upper.len());
        if upper[after_distinct..projection_end].contains(" COLLATE ") {
            return Err(DbError::sql(
                "COLLATE in DISTINCT keys is not supported in this compatibility slice",
            ));
        }
    }
    if let Some(group_by_index) = upper.find(" GROUP BY ") {
        let group_start = group_by_index + " GROUP BY ".len();
        let group_end = [" HAVING ", " ORDER BY ", " LIMIT ", " OFFSET "]
            .iter()
            .filter_map(|marker| {
                upper[group_start..]
                    .find(marker)
                    .map(|offset| group_start + offset)
            })
            .min()
            .unwrap_or(upper.len());
        if upper[group_start..group_end].contains(" COLLATE ") {
            return Err(DbError::sql(
                "COLLATE in GROUP BY keys is not supported in this compatibility slice",
            ));
        }
    }
    Ok(())
}

fn table_info(table: &TableSchema, row_count: usize) -> TableInfo {
    TableInfo {
        name: table.name.clone(),
        temporary: table.temporary,
        columns: table.columns.iter().map(column_info).collect(),
        checks: table
            .checks
            .iter()
            .map(|check| check.expression_sql.clone())
            .collect(),
        foreign_keys: table.foreign_keys.iter().map(foreign_key_info).collect(),
        primary_key_columns: table.primary_key_columns.clone(),
        row_count,
    }
}

fn column_info(column: &ColumnSchema) -> ColumnInfo {
    ColumnInfo {
        name: column.name.clone(),
        column_type: column.column_type.as_str().to_string(),
        nullable: column.nullable,
        default_sql: column.default_sql.clone(),
        primary_key: column.primary_key,
        unique: column.unique,
        auto_increment: column.auto_increment,
        checks: column
            .checks
            .iter()
            .map(|check| check.expression_sql.clone())
            .collect(),
        foreign_key: column.foreign_key.as_ref().map(foreign_key_info),
    }
}

fn foreign_key_info(foreign_key: &ForeignKeyConstraint) -> ForeignKeyInfo {
    ForeignKeyInfo {
        name: foreign_key.name.clone(),
        columns: foreign_key.columns.clone(),
        referenced_table: foreign_key.referenced_table.clone(),
        referenced_columns: foreign_key.referenced_columns.clone(),
        on_delete: foreign_key_action_name(foreign_key.on_delete).to_string(),
        on_update: foreign_key_action_name(foreign_key.on_update).to_string(),
    }
}

fn index_info(index: &IndexSchema) -> IndexInfo {
    IndexInfo {
        name: index.name.clone(),
        table_name: index.table_name.clone(),
        kind: match index.kind {
            IndexKind::Btree => "btree",
            IndexKind::Trigram => "trigram",
            IndexKind::Spatial => "spatial",
            IndexKind::FullText => "fulltext",
        }
        .to_string(),
        unique: index.unique,
        columns: index.columns.iter().map(index_column_name).collect(),
        include_columns: index.include_columns.clone(),
        predicate_sql: index.predicate_sql.clone(),
        full_text_options_json: full_text_options_json(index),
        fresh: index.fresh,
    }
}

fn view_info(view: &ViewSchema) -> ViewInfo {
    ViewInfo {
        name: view.name.clone(),
        temporary: view.temporary,
        sql_text: view.sql_text.clone(),
        column_names: view.column_names.clone(),
        dependencies: view.dependencies.clone(),
    }
}

fn trigger_info(trigger: &TriggerSchema) -> TriggerInfo {
    TriggerInfo {
        name: trigger.name.clone(),
        target_name: trigger.target_name.clone(),
        kind: trigger_kind_name(trigger.kind).to_string(),
        event: trigger_event_name(trigger.event).to_string(),
        on_view: trigger.on_view,
        action_sql: trigger.action_sql.clone(),
    }
}

fn schema_snapshot(db: &Db, runtime: &EngineRuntime) -> Result<SchemaSnapshot> {
    let mut tables = Vec::with_capacity(runtime.catalog.tables.len() + runtime.temp_tables.len());
    for table in runtime.catalog.tables.values() {
        if crate::sync::is_internal_table_name(&table.name) {
            continue;
        }
        tables.push(schema_table_info(
            table,
            db.runtime_table_row_count(runtime, &table.name)?,
        ));
    }
    for table in runtime.temp_tables.values() {
        tables.push(schema_table_info(
            table,
            db.runtime_table_row_count(runtime, &table.name)?,
        ));
    }
    tables.sort_by(|left, right| left.name.cmp(&right.name));

    let mut views = runtime
        .catalog
        .views
        .values()
        .map(schema_view_info)
        .collect::<Vec<_>>();
    views.extend(runtime.temp_views.values().map(schema_view_info));
    views.sort_by(|left, right| left.name.cmp(&right.name));

    let mut indexes = runtime
        .catalog
        .indexes
        .values()
        .map(schema_index_info)
        .collect::<Vec<_>>();
    indexes.sort_by(|left, right| left.name.cmp(&right.name));

    let mut triggers = runtime
        .catalog
        .triggers
        .values()
        .map(schema_trigger_info)
        .collect::<Vec<_>>();
    triggers.sort_by(|left, right| left.name.cmp(&right.name));

    Ok(SchemaSnapshot {
        snapshot_version: 1,
        schema_cookie: runtime.catalog.schema_cookie,
        tables,
        views,
        indexes,
        triggers,
    })
}

fn schema_table_info(table: &TableSchema, row_count: usize) -> SchemaTableInfo {
    SchemaTableInfo {
        name: table.name.clone(),
        temporary: table.temporary,
        ddl: render_create_table(table),
        row_count,
        primary_key_columns: table.primary_key_columns.clone(),
        checks: table.checks.iter().map(check_constraint_info).collect(),
        foreign_keys: table.foreign_keys.iter().map(foreign_key_info).collect(),
        columns: table.columns.iter().map(schema_column_info).collect(),
    }
}

fn schema_column_info(column: &ColumnSchema) -> SchemaColumnInfo {
    SchemaColumnInfo {
        name: column.name.clone(),
        column_type: column.column_type.as_str().to_string(),
        nullable: column.nullable,
        default_sql: column.default_sql.clone(),
        primary_key: column.primary_key,
        unique: column.unique,
        auto_increment: column.auto_increment,
        generated_sql: column.generated_sql.clone(),
        generated_stored: column.generated_stored,
        checks: column.checks.iter().map(check_constraint_info).collect(),
        foreign_key: column.foreign_key.as_ref().map(foreign_key_info),
    }
}

fn check_constraint_info(check: &CheckConstraint) -> CheckConstraintInfo {
    CheckConstraintInfo {
        name: check.name.clone(),
        expression_sql: check.expression_sql.clone(),
    }
}

fn schema_view_info(view: &ViewSchema) -> SchemaViewInfo {
    SchemaViewInfo {
        name: view.name.clone(),
        temporary: view.temporary,
        sql_text: view.sql_text.clone(),
        column_names: view.column_names.clone(),
        dependencies: view.dependencies.clone(),
        ddl: render_create_view(view),
    }
}

fn schema_index_info(index: &IndexSchema) -> SchemaIndexInfo {
    SchemaIndexInfo {
        name: index.name.clone(),
        table_name: index.table_name.clone(),
        kind: match index.kind {
            IndexKind::Btree => "btree",
            IndexKind::Trigram => "trigram",
            IndexKind::Spatial => "spatial",
            IndexKind::FullText => "fulltext",
        }
        .to_string(),
        unique: index.unique,
        columns: index.columns.iter().map(index_column_name).collect(),
        include_columns: index.include_columns.clone(),
        predicate_sql: index.predicate_sql.clone(),
        full_text_options_json: full_text_options_json(index),
        fresh: index.fresh,
        temporary: false,
        ddl: render_create_index(index),
    }
}

fn full_text_options_json(index: &IndexSchema) -> Option<String> {
    index
        .full_text
        .as_ref()
        .and_then(|config| String::from_utf8(config.to_json().ok()?).ok())
}

fn schema_trigger_info(trigger: &TriggerSchema) -> SchemaTriggerInfo {
    let event = trigger_event_name(trigger.event).to_ascii_lowercase();
    SchemaTriggerInfo {
        name: trigger.name.clone(),
        target_name: trigger.target_name.clone(),
        target_kind: if trigger.on_view {
            "view".to_string()
        } else {
            "table".to_string()
        },
        timing: match trigger.kind {
            TriggerKind::After => "after".to_string(),
            TriggerKind::InsteadOf => "instead_of".to_string(),
        },
        events: vec![event],
        events_mask: trigger_event_mask(trigger.event),
        for_each_row: true,
        temporary: false,
        action_sql: trigger.action_sql.clone(),
        ddl: render_create_trigger(trigger),
    }
}

fn trigger_event_mask(event: TriggerEvent) -> u32 {
    match event {
        TriggerEvent::Insert => 1,
        TriggerEvent::Update => 2,
        TriggerEvent::Delete => 4,
    }
}

fn index_column_name(column: &IndexColumn) -> String {
    if let Some(name) = &column.column_name {
        name.clone()
    } else if let Some(expression) = &column.expression_sql {
        expression.clone()
    } else {
        "<expr>".to_string()
    }
}

fn foreign_key_action_name(action: ForeignKeyAction) -> &'static str {
    match action {
        ForeignKeyAction::NoAction => "NO ACTION",
        ForeignKeyAction::Restrict => "RESTRICT",
        ForeignKeyAction::Cascade => "CASCADE",
        ForeignKeyAction::SetNull => "SET NULL",
    }
}

fn trigger_kind_name(kind: TriggerKind) -> &'static str {
    match kind {
        TriggerKind::After => "AFTER",
        TriggerKind::InsteadOf => "INSTEAD OF",
    }
}

fn trigger_event_name(event: TriggerEvent) -> &'static str {
    match event {
        TriggerEvent::Insert => "INSERT",
        TriggerEvent::Update => "UPDATE",
        TriggerEvent::Delete => "DELETE",
    }
}

fn runtime_index_entry_count(index: &RuntimeIndex) -> usize {
    match index {
        RuntimeIndex::Btree { keys, .. } => keys.total_row_id_count(),
        RuntimeIndex::Trigram { index } => index.entry_count(),
        RuntimeIndex::Spatial { index } => index.len(),
        RuntimeIndex::FullText { index } => index.entry_count(),
    }
}

struct MergePlan {
    source: String,
    target: String,
    base_head_id: String,
    table_count: usize,
    changes: Vec<MergeChangePlan>,
    conflicts: Vec<crate::branch::BranchMergeConflict>,
}

impl MergePlan {
    fn into_report(self, dry_run: bool) -> crate::branch::BranchMergeReport {
        crate::branch::BranchMergeReport {
            source: self.source,
            target: self.target,
            dry_run,
            clean: self.conflicts.is_empty(),
            base_head_id: self.base_head_id,
            table_count: self.table_count,
            applied_change_count: if dry_run || !self.conflicts.is_empty() {
                0
            } else {
                self.changes.len()
            },
            conflict_count: self.conflicts.len(),
            applied: if dry_run || !self.conflicts.is_empty() {
                Vec::new()
            } else {
                self.changes
                    .into_iter()
                    .map(|change| change.change)
                    .collect()
            },
            conflicts: self.conflicts,
        }
    }
}

struct MergeChangePlan {
    change: crate::branch::BranchMergeChange,
    sql: String,
}

struct MergeTableInputs<'a> {
    base_db: &'a Db,
    source_db: &'a Db,
    target_db: &'a Db,
    base_table: &'a TableInfo,
    source_table: &'a TableInfo,
    target_table: &'a TableInfo,
}

fn build_merge_plan(
    source_ref: &str,
    target_ref: &str,
    base_head_id: &str,
    base_db: &Db,
    source_db: &Db,
    target_db: &Db,
) -> Result<MergePlan> {
    let base_tables = table_info_map(base_db)?;
    let source_tables = table_info_map(source_db)?;
    let target_tables = table_info_map(target_db)?;
    let mut table_names = BTreeSet::new();
    table_names.extend(base_tables.keys().cloned());
    table_names.extend(source_tables.keys().cloned());
    table_names.extend(target_tables.keys().cloned());

    let mut changes = Vec::new();
    let mut conflicts = Vec::new();
    for table_name in &table_names {
        let Some(base_table) = base_tables.get(table_name) else {
            if source_tables.get(table_name) != target_tables.get(table_name) {
                conflicts.push(merge_conflict(
                    table_name,
                    Vec::new(),
                    "schema_change",
                    "merge does not support tables created after the branch base",
                ));
            }
            continue;
        };
        let Some(source_table) = source_tables.get(table_name) else {
            conflicts.push(merge_conflict(
                table_name,
                Vec::new(),
                "schema_change",
                "merge does not support dropped source tables",
            ));
            continue;
        };
        let Some(target_table) = target_tables.get(table_name) else {
            conflicts.push(merge_conflict(
                table_name,
                Vec::new(),
                "schema_change",
                "merge does not support dropped target tables",
            ));
            continue;
        };
        if !merge_table_schema_equal(base_table, source_table)
            || !merge_table_schema_equal(base_table, target_table)
        {
            conflicts.push(merge_conflict(
                table_name,
                Vec::new(),
                "schema_change",
                "merge supports identical table schemas only",
            ));
            continue;
        }
        if base_table.primary_key_columns.is_empty() {
            conflicts.push(merge_conflict(
                table_name,
                Vec::new(),
                "missing_primary_key",
                "merge requires primary-key tables",
            ));
            continue;
        }
        merge_table_rows(
            MergeTableInputs {
                base_db,
                source_db,
                target_db,
                base_table,
                source_table,
                target_table,
            },
            &mut changes,
            &mut conflicts,
        )?;
    }

    Ok(MergePlan {
        source: source_ref.to_string(),
        target: target_ref.to_string(),
        base_head_id: base_head_id.to_string(),
        table_count: table_names.len(),
        changes,
        conflicts,
    })
}

fn table_info_map(db: &Db) -> Result<BTreeMap<String, TableInfo>> {
    Ok(db
        .list_tables()?
        .into_iter()
        .map(|table| (table.name.clone(), table))
        .collect())
}

fn merge_table_rows(
    inputs: MergeTableInputs<'_>,
    changes: &mut Vec<MergeChangePlan>,
    conflicts: &mut Vec<crate::branch::BranchMergeConflict>,
) -> Result<()> {
    let base_rows = diff_table_rows(inputs.base_db, inputs.base_table)?;
    let source_rows = diff_table_rows(inputs.source_db, inputs.source_table)?;
    let target_rows = diff_table_rows(inputs.target_db, inputs.target_table)?;
    let mut row_keys = BTreeSet::new();
    row_keys.extend(base_rows.keys().cloned());
    row_keys.extend(source_rows.keys().cloned());
    row_keys.extend(target_rows.keys().cloned());

    for primary_key in row_keys {
        let base = base_rows.get(&primary_key);
        let source = source_rows.get(&primary_key);
        let target = target_rows.get(&primary_key);
        let source_changed = source != base;
        if !source_changed {
            continue;
        }
        let target_changed = target != base;
        if target_changed {
            if target == source {
                continue;
            }
            conflicts.push(merge_conflict(
                &inputs.base_table.name,
                primary_key,
                merge_conflict_type(base, source, target),
                "source and target changed the same primary-key row differently",
            ));
            continue;
        }
        let Some(change) =
            merge_change_for_source_delta(inputs.base_table, &primary_key, base, source)?
        else {
            continue;
        };
        changes.push(change);
    }
    Ok(())
}

fn merge_change_for_source_delta(
    table: &TableInfo,
    primary_key: &[String],
    base: Option<&Vec<String>>,
    source: Option<&Vec<String>>,
) -> Result<Option<MergeChangePlan>> {
    match (base, source) {
        (None, Some(after)) => Ok(Some(MergeChangePlan {
            change: crate::branch::BranchMergeChange {
                table: table.name.clone(),
                primary_key: primary_key.to_vec(),
                operation: crate::branch::BranchMergeOperation::Insert,
            },
            sql: merge_insert_sql(table, after),
        })),
        (Some(_), None) => Ok(Some(MergeChangePlan {
            change: crate::branch::BranchMergeChange {
                table: table.name.clone(),
                primary_key: primary_key.to_vec(),
                operation: crate::branch::BranchMergeOperation::Delete,
            },
            sql: merge_delete_sql(table, primary_key)?,
        })),
        (Some(_), Some(after)) => {
            let Some(sql) = merge_update_sql(table, primary_key, after)? else {
                return Ok(None);
            };
            Ok(Some(MergeChangePlan {
                change: crate::branch::BranchMergeChange {
                    table: table.name.clone(),
                    primary_key: primary_key.to_vec(),
                    operation: crate::branch::BranchMergeOperation::Update,
                },
                sql,
            }))
        }
        (None, None) => Ok(None),
    }
}

fn merge_insert_sql(table: &TableInfo, after: &[String]) -> String {
    let columns = table
        .columns
        .iter()
        .map(|column| sql_identifier(&column.name))
        .collect::<Vec<_>>()
        .join(", ");
    format!(
        "INSERT INTO {} ({columns}) VALUES ({});",
        sql_identifier(&table.name),
        after.join(", ")
    )
}

fn merge_delete_sql(table: &TableInfo, primary_key: &[String]) -> Result<String> {
    Ok(format!(
        "DELETE FROM {} WHERE {};",
        sql_identifier(&table.name),
        merge_where_clause(table, primary_key)?
    ))
}

fn merge_update_sql(
    table: &TableInfo,
    primary_key: &[String],
    after: &[String],
) -> Result<Option<String>> {
    let assignments = table
        .columns
        .iter()
        .enumerate()
        .filter(|(_, column)| {
            !table
                .primary_key_columns
                .iter()
                .any(|primary_key| identifiers_equal(primary_key, &column.name))
        })
        .map(|(index, column)| format!("{} = {}", sql_identifier(&column.name), after[index]))
        .collect::<Vec<_>>();
    if assignments.is_empty() {
        return Ok(None);
    }
    Ok(Some(format!(
        "UPDATE {} SET {} WHERE {};",
        sql_identifier(&table.name),
        assignments.join(", "),
        merge_where_clause(table, primary_key)?
    )))
}

fn merge_where_clause(table: &TableInfo, primary_key: &[String]) -> Result<String> {
    if primary_key.len() != table.primary_key_columns.len() {
        return Err(DbError::internal("merge primary-key arity mismatch"));
    }
    Ok(table
        .primary_key_columns
        .iter()
        .zip(primary_key.iter())
        .map(|(column, value)| format!("{} = {value}", sql_identifier(column)))
        .collect::<Vec<_>>()
        .join(" AND "))
}

fn merge_conflict_type(
    base: Option<&Vec<String>>,
    source: Option<&Vec<String>>,
    target: Option<&Vec<String>>,
) -> &'static str {
    match (base, source, target) {
        (None, Some(_), Some(_)) => "duplicate_insert",
        (Some(_), None, Some(_)) => "delete_update",
        (Some(_), Some(_), None) => "update_delete",
        (Some(_), Some(_), Some(_)) => "update_update",
        _ => "row_conflict",
    }
}

fn merge_conflict(
    table: &str,
    primary_key: Vec<String>,
    conflict_type: &str,
    message: &str,
) -> crate::branch::BranchMergeConflict {
    crate::branch::BranchMergeConflict {
        table: table.to_string(),
        primary_key,
        conflict_type: conflict_type.to_string(),
        message: message.to_string(),
    }
}

fn merge_table_schema_equal(left: &TableInfo, right: &TableInfo) -> bool {
    left.columns == right.columns
        && left.checks == right.checks
        && left.foreign_keys == right.foreign_keys
        && left.primary_key_columns == right.primary_key_columns
}

fn diff_materialized_refs(
    left_ref: &str,
    right_ref: &str,
    left_db: &Db,
    right_db: &Db,
) -> Result<crate::branch::BranchDiffReport> {
    let left_tables = left_db
        .list_tables()?
        .into_iter()
        .map(|table| (table.name.clone(), table))
        .collect::<BTreeMap<_, _>>();
    let right_tables = right_db
        .list_tables()?
        .into_iter()
        .map(|table| (table.name.clone(), table))
        .collect::<BTreeMap<_, _>>();
    let mut table_names = BTreeSet::new();
    table_names.extend(left_tables.keys().cloned());
    table_names.extend(right_tables.keys().cloned());

    let mut tables = Vec::new();
    for table_name in table_names {
        let table_diff = match (left_tables.get(&table_name), right_tables.get(&table_name)) {
            (None, Some(right_table)) => {
                let (added, message) = diff_rows_for_added_table(right_db, right_table)?;
                crate::branch::BranchTableDiff {
                    table: table_name,
                    status: crate::branch::BranchTableDiffStatus::Added,
                    schema_changed: true,
                    added,
                    updated: Vec::new(),
                    deleted: Vec::new(),
                    message,
                }
            }
            (Some(left_table), None) => {
                let (deleted, message) = diff_rows_for_removed_table(left_db, left_table)?;
                crate::branch::BranchTableDiff {
                    table: table_name,
                    status: crate::branch::BranchTableDiffStatus::Removed,
                    schema_changed: true,
                    added: Vec::new(),
                    updated: Vec::new(),
                    deleted,
                    message,
                }
            }
            (Some(left_table), Some(right_table)) => {
                diff_existing_table(left_db, right_db, left_table, right_table)?
            }
            (None, None) => continue,
        };
        tables.push(table_diff);
    }

    let added_row_count = tables.iter().map(|table| table.added.len()).sum();
    let updated_row_count = tables.iter().map(|table| table.updated.len()).sum();
    let deleted_row_count = tables.iter().map(|table| table.deleted.len()).sum();
    let changed_table_count = tables
        .iter()
        .filter(|table| table.status != crate::branch::BranchTableDiffStatus::Unchanged)
        .count();

    Ok(crate::branch::BranchDiffReport {
        left_ref: left_ref.to_string(),
        right_ref: right_ref.to_string(),
        table_count: tables.len(),
        changed_table_count,
        added_row_count,
        updated_row_count,
        deleted_row_count,
        tables,
    })
}

fn diff_existing_table(
    left_db: &Db,
    right_db: &Db,
    left_table: &TableInfo,
    right_table: &TableInfo,
) -> Result<crate::branch::BranchTableDiff> {
    let schema_changed = left_table.columns != right_table.columns
        || left_table.checks != right_table.checks
        || left_table.foreign_keys != right_table.foreign_keys
        || left_table.primary_key_columns != right_table.primary_key_columns;
    if left_table.primary_key_columns.is_empty() || right_table.primary_key_columns.is_empty() {
        let changed = schema_changed || left_table.row_count != right_table.row_count;
        return Ok(crate::branch::BranchTableDiff {
            table: left_table.name.clone(),
            status: if changed {
                crate::branch::BranchTableDiffStatus::Unsupported
            } else {
                crate::branch::BranchTableDiffStatus::Unchanged
            },
            schema_changed,
            added: Vec::new(),
            updated: Vec::new(),
            deleted: Vec::new(),
            message: Some(
                "row diff requires a primary key; table-level metadata was compared only"
                    .to_string(),
            ),
        });
    }
    if left_table.primary_key_columns != right_table.primary_key_columns {
        return Ok(crate::branch::BranchTableDiff {
            table: left_table.name.clone(),
            status: crate::branch::BranchTableDiffStatus::Unsupported,
            schema_changed,
            added: Vec::new(),
            updated: Vec::new(),
            deleted: Vec::new(),
            message: Some("primary-key columns differ; row diff is not supported".to_string()),
        });
    }

    let left_rows = diff_table_rows(left_db, left_table)?;
    let right_rows = diff_table_rows(right_db, right_table)?;
    let mut keys = BTreeSet::new();
    keys.extend(left_rows.keys().cloned());
    keys.extend(right_rows.keys().cloned());

    let mut added = Vec::new();
    let mut updated = Vec::new();
    let mut deleted = Vec::new();
    for key in keys {
        match (left_rows.get(&key), right_rows.get(&key)) {
            (None, Some(after)) => added.push(crate::branch::BranchRowDiff {
                primary_key: key,
                before: None,
                after: Some(after.clone()),
            }),
            (Some(before), None) => deleted.push(crate::branch::BranchRowDiff {
                primary_key: key,
                before: Some(before.clone()),
                after: None,
            }),
            (Some(before), Some(after)) if before != after => {
                updated.push(crate::branch::BranchRowDiff {
                    primary_key: key,
                    before: Some(before.clone()),
                    after: Some(after.clone()),
                });
            }
            _ => {}
        }
    }

    let changed = schema_changed || !added.is_empty() || !updated.is_empty() || !deleted.is_empty();
    Ok(crate::branch::BranchTableDiff {
        table: left_table.name.clone(),
        status: if changed {
            crate::branch::BranchTableDiffStatus::Changed
        } else {
            crate::branch::BranchTableDiffStatus::Unchanged
        },
        schema_changed,
        added,
        updated,
        deleted,
        message: None,
    })
}

fn diff_rows_for_added_table(
    db: &Db,
    table: &TableInfo,
) -> Result<(Vec<crate::branch::BranchRowDiff>, Option<String>)> {
    if table.primary_key_columns.is_empty() {
        return Ok((
            Vec::new(),
            Some("row diff requires a primary key; table is reported as added".to_string()),
        ));
    }
    let rows = diff_table_rows(db, table)?
        .into_iter()
        .map(|(primary_key, after)| crate::branch::BranchRowDiff {
            primary_key,
            before: None,
            after: Some(after),
        })
        .collect();
    Ok((rows, None))
}

fn diff_rows_for_removed_table(
    db: &Db,
    table: &TableInfo,
) -> Result<(Vec<crate::branch::BranchRowDiff>, Option<String>)> {
    if table.primary_key_columns.is_empty() {
        return Ok((
            Vec::new(),
            Some("row diff requires a primary key; table is reported as removed".to_string()),
        ));
    }
    let rows = diff_table_rows(db, table)?
        .into_iter()
        .map(|(primary_key, before)| crate::branch::BranchRowDiff {
            primary_key,
            before: Some(before),
            after: None,
        })
        .collect();
    Ok((rows, None))
}

fn diff_table_rows(db: &Db, table: &TableInfo) -> Result<BTreeMap<Vec<String>, Vec<String>>> {
    let columns = table
        .columns
        .iter()
        .map(|column| sql_identifier(&column.name))
        .collect::<Vec<_>>()
        .join(", ");
    let order_by = table
        .primary_key_columns
        .iter()
        .map(|column| sql_identifier(column))
        .collect::<Vec<_>>()
        .join(", ");
    let sql = format!(
        "SELECT {columns} FROM {} ORDER BY {order_by}",
        sql_identifier(&table.name)
    );
    let result = db.execute(&sql)?;
    let primary_key_indexes = table
        .primary_key_columns
        .iter()
        .map(|primary_key| {
            table
                .columns
                .iter()
                .position(|column| identifiers_equal(&column.name, primary_key))
                .ok_or_else(|| {
                    DbError::corruption(format!(
                        "primary-key column '{primary_key}' missing from table '{}'",
                        table.name
                    ))
                })
        })
        .collect::<Result<Vec<_>>>()?;

    let mut rows = BTreeMap::new();
    for row in result.rows() {
        let values = row
            .values()
            .iter()
            .map(diff_value_string)
            .collect::<Vec<_>>();
        let primary_key = primary_key_indexes
            .iter()
            .map(|index| values[*index].clone())
            .collect::<Vec<_>>();
        rows.insert(primary_key, values);
    }
    Ok(rows)
}

fn diff_value_string(value: &Value) -> String {
    render_value_sql(value)
}

fn render_runtime_dump(
    db: &Db,
    runtime: &mut EngineRuntime,
    snapshot_lsn: Option<u64>,
) -> Result<String> {
    let mut lines = Vec::new();

    for table in runtime.catalog.tables.values() {
        lines.push(render_create_table(table));
    }
    let table_names = runtime.catalog.tables.keys().cloned().collect::<Vec<_>>();
    for table_name in table_names {
        db.ensure_inspection_table_row_source(runtime, &table_name, snapshot_lsn)?;
        let table = runtime
            .catalog
            .table(&table_name)
            .cloned()
            .ok_or_else(|| DbError::internal(format!("unknown table {table_name}")))?;
        let row_source = runtime.table_row_source(&table.name).ok_or_else(|| {
            DbError::internal(format!("table row source for {} is missing", table.name))
        })?;
        for row in row_source.rows() {
            lines.push(render_insert(&table, row?.values()));
        }
        db.redefer_inspection_table_row_source(runtime, &table_name, snapshot_lsn);
    }
    for view in runtime.catalog.views.values() {
        lines.push(render_create_view(view));
    }
    for table in runtime.temp_tables.values() {
        lines.push(render_create_table(table));
    }
    for (table_name, table_data) in runtime.temp_table_data.iter() {
        if let Some(table) = runtime.temp_tables.get(table_name) {
            for row in &table_data.rows {
                lines.push(render_insert(table, &row.values));
            }
        }
    }
    for view in runtime.temp_views.values() {
        lines.push(render_create_view(view));
    }
    for index in runtime.catalog.indexes.values() {
        if runtime
            .catalog
            .table(&index.table_name)
            .is_some_and(|table| is_auto_table_index(table, index))
        {
            continue;
        }
        lines.push(render_create_index(index));
    }
    for trigger in runtime.catalog.triggers.values() {
        lines.push(render_create_trigger(trigger));
    }

    Ok(lines.join("\n"))
}

fn render_create_table(table: &TableSchema) -> String {
    let mut definitions = Vec::new();
    for column in &table.columns {
        let mut definition = format!(
            "{} {}",
            sql_identifier(&column.name),
            render_column_type(column)
        );
        if !column.nullable {
            definition.push_str(" NOT NULL");
        }
        if column.primary_key {
            definition.push_str(" PRIMARY KEY");
        }
        if column.unique {
            definition.push_str(" UNIQUE");
        }
        if let Some(generated_sql) = &column.generated_sql {
            definition.push_str(" GENERATED ALWAYS AS (");
            definition.push_str(generated_sql);
            if column.generated_stored {
                definition.push_str(") STORED");
            } else {
                definition.push_str(") VIRTUAL");
            }
        } else if let Some(default_sql) = &column.default_sql {
            definition.push_str(" DEFAULT ");
            definition.push_str(default_sql);
        }
        for check in &column.checks {
            definition.push_str(" CHECK (");
            definition.push_str(&check.expression_sql);
            definition.push(')');
        }
        if let Some(foreign_key) = &column.foreign_key {
            definition.push(' ');
            definition.push_str(&render_foreign_key(foreign_key));
        }
        definitions.push(definition);
    }

    if table.primary_key_columns.len() > 1 {
        definitions.push(format!(
            "PRIMARY KEY ({})",
            table
                .primary_key_columns
                .iter()
                .map(|name| sql_identifier(name))
                .collect::<Vec<_>>()
                .join(", ")
        ));
    }
    for foreign_key in &table.foreign_keys {
        definitions.push(render_foreign_key(foreign_key));
    }
    for check in &table.checks {
        definitions.push(format!("CHECK ({})", check.expression_sql));
    }

    format!(
        "CREATE {}TABLE {} ({});",
        if table.temporary { "TEMP " } else { "" },
        sql_identifier(&table.name),
        definitions.join(", ")
    )
}

fn render_foreign_key(foreign_key: &ForeignKeyConstraint) -> String {
    let mut sql = String::new();
    if let Some(name) = &foreign_key.name {
        sql.push_str("CONSTRAINT ");
        sql.push_str(&sql_identifier(name));
        sql.push(' ');
    }
    sql.push_str("FOREIGN KEY (");
    sql.push_str(
        &foreign_key
            .columns
            .iter()
            .map(|name| sql_identifier(name))
            .collect::<Vec<_>>()
            .join(", "),
    );
    sql.push_str(") REFERENCES ");
    sql.push_str(&sql_identifier(&foreign_key.referenced_table));
    sql.push_str(" (");
    sql.push_str(
        &foreign_key
            .referenced_columns
            .iter()
            .map(|name| sql_identifier(name))
            .collect::<Vec<_>>()
            .join(", "),
    );
    sql.push(')');
    if foreign_key.on_delete != ForeignKeyAction::NoAction {
        sql.push_str(" ON DELETE ");
        sql.push_str(foreign_key_action_name(foreign_key.on_delete));
    }
    if foreign_key.on_update != ForeignKeyAction::NoAction {
        sql.push_str(" ON UPDATE ");
        sql.push_str(foreign_key_action_name(foreign_key.on_update));
    }
    sql
}

fn render_insert(table: &TableSchema, values: &[Value]) -> String {
    let columns = table
        .columns
        .iter()
        .map(|column| sql_identifier(&column.name))
        .collect::<Vec<_>>()
        .join(", ");
    let values = values
        .iter()
        .zip(table.columns.iter())
        .map(|(value, column)| render_column_value_sql(column, value))
        .collect::<Vec<_>>()
        .join(", ");
    format!(
        "INSERT INTO {} ({columns}) VALUES ({values});",
        sql_identifier(&table.name)
    )
}

fn render_column_type(column: &crate::catalog::ColumnSchema) -> String {
    if column.column_type == crate::catalog::ColumnType::Enum {
        if let Some(enum_type) = &column.enum_type {
            let labels = enum_type
                .labels
                .iter()
                .map(|label| sql_string_literal(&label.label))
                .collect::<Vec<_>>()
                .join(", ");
            return format!("ENUM({labels})");
        }
    }
    column.column_type.as_str().to_string()
}

fn render_column_value_sql(column: &crate::catalog::ColumnSchema, value: &Value) -> String {
    if let (
        crate::catalog::ColumnType::Enum,
        Some(enum_type),
        Value::Enum {
            enum_type_id,
            label_id,
        },
    ) = (column.column_type, &column.enum_type, value)
    {
        if *enum_type_id == enum_type.type_id {
            if let Some(label) = enum_type.label_for_id(*label_id) {
                return sql_string_literal(label);
            }
        }
    }
    render_value_sql(value)
}

fn render_create_view(view: &ViewSchema) -> String {
    let columns = if view.column_names.is_empty() {
        String::new()
    } else {
        format!(
            " ({})",
            view.column_names
                .iter()
                .map(|name| sql_identifier(name))
                .collect::<Vec<_>>()
                .join(", ")
        )
    };
    format!(
        "CREATE {}VIEW {}{columns} AS {};",
        if view.temporary { "TEMP " } else { "" },
        sql_identifier(&view.name),
        view.sql_text
    )
}

fn render_create_index(index: &IndexSchema) -> String {
    let unique = if index.unique { "UNIQUE " } else { "" };
    let using = match index.kind {
        IndexKind::Btree => String::new(),
        IndexKind::Trigram => " USING trigram".to_string(),
        IndexKind::Spatial => " USING spatial".to_string(),
        IndexKind::FullText => " USING fulltext".to_string(),
    };
    let full_text_options = render_full_text_options(index.full_text.as_ref());
    let columns = index
        .columns
        .iter()
        .map(index_column_name)
        .collect::<Vec<_>>()
        .join(", ");
    let include = if index.include_columns.is_empty() {
        String::new()
    } else {
        format!(
            " INCLUDE ({})",
            index
                .include_columns
                .iter()
                .map(|column| sql_identifier(column))
                .collect::<Vec<_>>()
                .join(", ")
        )
    };
    let predicate = index
        .predicate_sql
        .as_ref()
        .map(|predicate| format!(" WHERE {predicate}"))
        .unwrap_or_default();
    format!(
        "CREATE {unique}INDEX {} ON {}{using} ({columns}){full_text_options}{include}{predicate};",
        sql_identifier(&index.name),
        sql_identifier(&index.table_name)
    )
}

fn render_full_text_options(config: Option<&AnalyzerConfig>) -> String {
    let Some(config) = config else {
        return String::new();
    };
    let tokenizer = match config.tokenizer {
        AnalyzerTokenization::Unicode => "unicode",
    };
    let language = match config.language {
        AnalyzerLanguage::Simple => "simple",
        AnalyzerLanguage::English => "english",
    };
    let stopwords = match &config.stopwords {
        AnalyzerStopwords::None => "none".to_string(),
        AnalyzerStopwords::Builtin => "builtin".to_string(),
        AnalyzerStopwords::Custom(words) => words.join(","),
    };
    let stemming = match config.stemming {
        AnalyzerStemmer::None => "none",
        AnalyzerStemmer::English => "english",
    };
    let diacritics = match config.diacritics {
        AnalyzerDiacritics::Preserve => "preserve",
        AnalyzerDiacritics::Remove => "remove",
    };
    let prefix = if config.prefix.enabled {
        config
            .prefix
            .lengths
            .iter()
            .map(u8::to_string)
            .collect::<Vec<_>>()
            .join(",")
    } else {
        "none".to_string()
    };
    format!(
        " WITH (tokenizer = {}, language = {}, stopwords = {}, stemming = {}, case_folded = {}, diacritics = {}, prefix = {})",
        sql_string_literal(tokenizer),
        sql_string_literal(language),
        sql_string_literal(&stopwords),
        sql_string_literal(stemming),
        if config.case_folded { "TRUE" } else { "FALSE" },
        sql_string_literal(diacritics),
        sql_string_literal(&prefix),
    )
}

fn is_auto_table_index(table: &TableSchema, index: &IndexSchema) -> bool {
    let Some(column_names) = index_column_names(index) else {
        return false;
    };
    if !index.include_columns.is_empty() || index.predicate_sql.is_some() {
        return false;
    }
    if !identifiers_equal(&index.table_name, &table.name) || index.kind != IndexKind::Btree {
        return false;
    }
    if !table.primary_key_columns.is_empty()
        && index.unique
        && identifier_lists_equal(&column_names, &table.primary_key_columns)
        && identifiers_equal(
            &index.name,
            &dump_auto_index_name("pk", &table.name, &table.primary_key_columns),
        )
    {
        return true;
    }
    if column_names.len() == 1
        && index.unique
        && table.columns.iter().any(|column| {
            column.unique
                && !column.primary_key
                && identifiers_equal(&column.name, &column_names[0])
                && identifiers_equal(
                    &index.name,
                    &dump_auto_index_name("uq", &table.name, &column_names),
                )
        })
    {
        return true;
    }
    table.foreign_keys.iter().any(|foreign_key| {
        !index.unique
            && identifier_lists_equal(&column_names, &foreign_key.columns)
            && identifiers_equal(
                &index.name,
                &format!(
                    "{}_idx",
                    dump_auto_index_name("fk", &table.name, &foreign_key.columns)
                ),
            )
    })
}

fn index_column_names(index: &IndexSchema) -> Option<Vec<String>> {
    index
        .columns
        .iter()
        .map(|column| column.column_name.clone())
        .collect()
}

fn identifier_lists_equal(left: &[String], right: &[String]) -> bool {
    left.len() == right.len()
        && left
            .iter()
            .zip(right.iter())
            .all(|(left, right)| identifiers_equal(left, right))
}

fn dump_auto_index_name(prefix: &str, table_name: &str, columns: &[String]) -> String {
    format!("{prefix}_{}_{}", table_name, columns.join("_"))
}

fn render_create_trigger(trigger: &TriggerSchema) -> String {
    format!(
        "CREATE TRIGGER {} {} {} ON {} FOR EACH ROW EXECUTE FUNCTION decentdb_exec_sql({});",
        sql_identifier(&trigger.name),
        trigger_kind_name(trigger.kind),
        trigger_event_name(trigger.event),
        sql_identifier(&trigger.target_name),
        render_value_sql(&Value::Text(trigger.action_sql.clone()))
    )
}

fn render_value_sql(value: &Value) -> String {
    match value {
        Value::Null => "NULL".to_string(),
        Value::Int64(value) => value.to_string(),
        Value::Float64(value) => {
            if value.is_finite() {
                value.to_string()
            } else {
                "NULL".to_string()
            }
        }
        Value::Bool(value) => {
            if *value {
                "TRUE".to_string()
            } else {
                "FALSE".to_string()
            }
        }
        Value::Text(value) => sql_string_literal(value),
        Value::Blob(value) => format!("X'{}'", hex_encode(value)),
        Value::Geometry(value) | Value::Geography(value) => format!("X'{}'", hex_encode(value)),
        Value::Decimal { scaled, scale } => decimal_sql_text(*scaled, *scale),
        Value::Uuid(value) => format!("X'{}'", hex_encode(value)),
        Value::TimestampMicros(value) => value.to_string(),
        Value::Enum {
            enum_type_id,
            label_id,
        } => format!("'{enum_type_id}:{label_id}'"),
        Value::IpAddr { family, addr } => match format_ip_addr(*family, addr) {
            Ok(value) => format!("'{value}'"),
            Err(_) => "NULL".to_string(),
        },
        Value::Cidr {
            family,
            prefix_len,
            network,
        } => match format_cidr(*family, *prefix_len, network) {
            Ok(value) => format!("'{value}'"),
            Err(_) => "NULL".to_string(),
        },
        Value::MacAddr { len, bytes } => match format_mac_addr(*len, bytes) {
            Ok(value) => format!("'{value}'"),
            Err(_) => "NULL".to_string(),
        },
        Value::DateDays(days) => format!("'{}'", format_date_days(*days)),
        Value::TimeMicros(micros) => match format_time_micros(*micros) {
            Ok(value) => format!("'{value}'"),
            Err(_) => "NULL".to_string(),
        },
        Value::TimestampTzMicros(micros) => {
            format!("'{}'", format_timestamp_tz_micros(*micros))
        }
        Value::Interval {
            months,
            days,
            micros,
        } => format!("'{}'", format_interval(*months, *days, *micros)),
    }
}

fn render_branch_parameter_value_sql(value: &Value) -> Result<String> {
    match value {
        Value::Decimal { scaled, scale } => Ok(format!(
            "CAST({} AS DECIMAL)",
            sql_string_literal(&decimal_sql_text(*scaled, *scale))
        )),
        Value::Uuid(value) => Ok(format!(
            "UUID_PARSE({})",
            sql_string_literal(&hex_encode(value))
        )),
        Value::TimestampMicros(value) => Ok(format!(
            "CAST({} AS TIMESTAMP)",
            sql_string_literal(&format_timestamp_tz_micros(*value))
        )),
        Value::TimestampTzMicros(value) => Ok(format!(
            "CAST({} AS TIMESTAMP WITH TIME ZONE)",
            sql_string_literal(&format_timestamp_tz_micros(*value))
        )),
        Value::DateDays(days) => Ok(format!(
            "CAST({} AS DATE)",
            sql_string_literal(&format_date_days(*days))
        )),
        Value::TimeMicros(micros) => Ok(format!(
            "CAST({} AS TIME)",
            sql_string_literal(&format_time_micros(*micros)?)
        )),
        Value::Interval {
            months,
            days,
            micros,
        } => Ok(format!(
            "CAST({} AS INTERVAL)",
            sql_string_literal(&format_interval(*months, *days, *micros))
        )),
        Value::IpAddr { family, addr } => Ok(format!(
            "CAST({} AS IPADDR)",
            sql_string_literal(&format_ip_addr(*family, addr)?)
        )),
        Value::Cidr {
            family,
            prefix_len,
            network,
        } => Ok(format!(
            "CAST({} AS CIDR)",
            sql_string_literal(&format_cidr(*family, *prefix_len, network)?)
        )),
        Value::MacAddr { len, bytes } => Ok(format!(
            "CAST({} AS MACADDR)",
            sql_string_literal(&format_mac_addr(*len, bytes)?)
        )),
        Value::Geometry(value) => Ok(format!("ST_GeomFromWKB(X'{}')", hex_encode(value))),
        Value::Geography(value) => Ok(format!("ST_GeogFromWKB(X'{}')", hex_encode(value))),
        _ => Ok(render_value_sql(value)),
    }
}

fn decimal_sql_text(scaled: i64, scale: u8) -> String {
    if scale == 0 {
        scaled.to_string()
    } else {
        let negative = scaled < 0;
        let digits = scaled.unsigned_abs().to_string();
        let scale = usize::from(scale);
        let padded = if digits.len() <= scale {
            format!("{}{}", "0".repeat(scale + 1 - digits.len()), digits)
        } else {
            digits
        };
        let split = padded.len() - scale;
        let mut decimal = format!("{}.{}", &padded[..split], &padded[split..]);
        if negative {
            decimal.insert(0, '-');
        }
        decimal
    }
}

fn sql_identifier(name: &str) -> String {
    format!("\"{}\"", name.replace('"', "\"\""))
}

fn sql_string_literal(value: &str) -> String {
    format!("'{}'", value.replace('\'', "''"))
}

fn audit_context_json(context: &BTreeMap<String, Value>) -> Result<String> {
    let mut object = serde_json::Map::new();
    for (key, value) in context {
        object.insert(key.clone(), audit_value_to_json(value));
    }
    serde_json::to_string(&JsonValue::Object(object))
        .map_err(|error| DbError::internal(format!("serialize audit context JSON: {error}")))
}

fn audit_value_to_json(value: &Value) -> JsonValue {
    match value {
        Value::Null => JsonValue::Null,
        Value::Int64(value) => JsonValue::Number(serde_json::Number::from(*value)),
        Value::Float64(value) => serde_json::Number::from_f64(*value)
            .map(JsonValue::Number)
            .unwrap_or(JsonValue::Null),
        Value::Bool(value) => JsonValue::Bool(*value),
        Value::Text(value) => JsonValue::String(value.clone()),
        Value::Blob(value) | Value::Geometry(value) | Value::Geography(value) => {
            JsonValue::String(hex_encode(value))
        }
        Value::Decimal { scaled, scale } => JsonValue::String(decimal_to_text(*scaled, *scale)),
        Value::Uuid(value) => JsonValue::String(hex_encode(value)),
        Value::TimestampMicros(value) => JsonValue::Number(serde_json::Number::from(*value)),
        Value::Enum {
            enum_type_id,
            label_id,
        } => JsonValue::String(format!("{enum_type_id}:{label_id}")),
        Value::IpAddr { family, addr } => format_ip_addr(*family, addr)
            .map(JsonValue::String)
            .unwrap_or(JsonValue::Null),
        Value::Cidr {
            family,
            prefix_len,
            network,
        } => format_cidr(*family, *prefix_len, network)
            .map(JsonValue::String)
            .unwrap_or(JsonValue::Null),
        Value::MacAddr { len, bytes } => format_mac_addr(*len, bytes)
            .map(JsonValue::String)
            .unwrap_or(JsonValue::Null),
        Value::DateDays(value) => JsonValue::String(format_date_days(*value)),
        Value::TimeMicros(value) => format_time_micros(*value)
            .map(JsonValue::String)
            .unwrap_or(JsonValue::Null),
        Value::TimestampTzMicros(value) => JsonValue::String(format_timestamp_tz_micros(*value)),
        Value::Interval {
            months,
            days,
            micros,
        } => JsonValue::String(format_interval(*months, *days, *micros)),
    }
}

fn audit_value_to_text(value: &Value) -> String {
    match value {
        Value::Text(value) => value.clone(),
        Value::Null => "null".to_string(),
        other => audit_value_to_json(other).to_string(),
    }
}

fn decimal_to_text(scaled: i64, scale: u8) -> String {
    if scale == 0 {
        return scaled.to_string();
    }
    let negative = scaled < 0;
    let digits = scaled.unsigned_abs().to_string();
    let scale = usize::from(scale);
    let padded = if digits.len() <= scale {
        format!("{}{}", "0".repeat(scale + 1 - digits.len()), digits)
    } else {
        digits
    };
    let split = padded.len() - scale;
    let mut decimal = format!("{}.{}", &padded[..split], &padded[split..]);
    if negative {
        decimal.insert(0, '-');
    }
    decimal
}

fn hex_encode(bytes: &[u8]) -> String {
    let mut output = String::with_capacity(bytes.len() * 2);
    for byte in bytes {
        use std::fmt::Write as _;

        let _ = write!(output, "{byte:02x}");
    }
    output
}

fn json_escape(input: String) -> String {
    input
        .replace('\\', "\\\\")
        .replace('"', "\\\"")
        .replace('\n', "\\n")
}

